const express = require('express');
const cors = require('cors');
const http = require('http');
const { createProxyMiddleware } = require('http-proxy-middleware');

const app = express();
const PORT = process.env.PORT || 3000;

// Configuration for your target services
// In a real-world scenario, you might load these from a config file or environment variables
const services = {
  userService: {
    target: 'http://localhost:3001', // Example target URL for user service
    path: '/users', // Base path for this service
  },
  productService: {
    target: 'http://localhost:3002', // Example target URL for product service
    path: '/products', // Base path for this service
  },
  orderService: {
    target: 'http://localhost:3003', // Example target URL for order service
    path: '/orders', // Base path for this service
  },
  // Add more services as needed
};

// Enable CORS for all routes and origins
// Allowing all origins, methods, and headers for simplified frontend development.
// In a production environment, you might want to restrict origins for security.
app.use(cors({
  origin: '*', // Allow all origins
  methods: 'GET,HEAD,PUT,PATCH,POST,DELETE', // Allow all common HTTP methods
  allowedHeaders: '*', // Allow all headers
  credentials: true, // Allow cookies to be sent
}));

// Setup proxy for each defined service
for (const serviceName in services) {
  const service = services[serviceName];
  app.use(
    service.path,
    createProxyMiddleware({
      target: service.target,
      changeOrigin: true, // Needed for virtual hosted sites
      ws: true, // Enable proxying of WebSockets
      pathRewrite: {
        [`^${service.path}`]: '', // Remove the base path when forwarding to the target
      },
      onProxyReq: (proxyReq, req, res) => {
        // Optional: Add/modify headers before forwarding the request
        // console.log(`Proxying request for ${service.path} to ${service.target}${req.url}`);
        // console.log('Original headers:', req.headers);
        // console.log('Proxying headers:', proxyReq.getHeaders());
      },
      onProxyRes: (proxyRes, req, res) => {
        // Optional: Modify the response from the target service
        // console.log(`Received response from ${service.target}${req.url} with status ${proxyRes.statusCode}`);
        // console.log('Response headers:', proxyRes.headers);
        // Add or overwrite CORS headers to ensure they are present, even if the backend doesn't set them
        // This is redundant with app.use(cors()) but provides a fallback
        proxyRes.headers['Access-Control-Allow-Origin'] = '*';
        proxyRes.headers['Access-Control-Allow-Methods'] = 'GET,HEAD,PUT,PATCH,POST,DELETE';
        proxyRes.headers['Access-Control-Allow-Headers'] = '*';
      },
      onError: (err, req, res) => {
        console.error(`Proxy error for ${req.url}:`, err);
        res.status(500).json({
          error: 'Proxy error',
          message: err.message
        });
      }
    })
  );
}

// Basic health check endpoint
app.get('/health', (req, res) => {
  res.status(200).json({ status: 'API Gateway is up and running!' });
});

// Catch-all for any undefined routes
app.use((req, res) => {
  res.status(404).json({ error: 'Not Found', message: `No route defined for ${req.method} ${req.url}` });
});

// Start the API Gateway server
const server = http.createServer(app);

server.listen(PORT, () => {
  console.log(`API Gateway listening on port ${PORT}`);
  console.log('Registered services:');
  for (const serviceName in services) {
    const service = services[serviceName];
    console.log(`  - ${serviceName}: ${service.path} -> ${service.target}`);
  }
  console.log(`CORS is configured to allow all origins, methods, and headers.`);
});

// Handle graceful shutdown
process.on('SIGTERM', () => {
  console.log('SIGTERM signal received: closing HTTP server');
  server.close(() => {
    console.log('HTTP server closed');
    process.exit(0);
  });
});

process.on('SIGINT', () => {
  console.log('SIGINT signal received: closing HTTP server');
  server.close(() => {
    console.log('HTTP server closed');
    process.exit(0);
  });
});